int num_of_reads = 0;
void dummy_i2s_channel_read(int rx_handle, int32_t* returnBuffer, size_t bytes_to_read, size_t *bytes_read, int maxdelaytime_ms){
   for (size_t i=0; i<bytes_to_read/4;i++)
    returnBuffer[i]=features[num_of_reads + i];
   *bytes_read = bytes_to_read;
   num_of_reads += bytes_to_read/4;
   vTaskDelay((bytes_to_read/4)*(21));
   //you will get an error if bytes_to_read>features[num_of_reads:]
}
/** 
 * This marks the end of the i2s simulator
 * **/

#define EI_CLASSIFIER_SLICES_PER_MODEL_WINDOW 4

/** Audio buffers, pointers and selectors */
typedef struct {
    int32_t *buffers[2]; // The size will be 
    unsigned char buf_select;
    unsigned char buf_ready;
    unsigned int buf_count;
    unsigned int n_samples;
} inference_t;

inference_t inference;
const uint32_t sample_buffer_size = 2048;
int32_t sampleBuffer[sample_buffer_size];
bool debug_nn = false; // Set this to true to see e.g. features generated from the raw signal
int print_results = -(EI_CLASSIFIER_SLICES_PER_MODEL_WINDOW);
static bool record_status = true;

void audio_inference_callback(uint32_t n_bytes)
{
    for(int i = 0; i < n_bytes>>1; i++) {
        inference.buffers[inference.buf_select][inference.buf_count++] = sampleBuffer[i];

        if(inference.buf_count >= inference.n_samples) {
            inference.buf_select ^= 1;
            inference.buf_count = 0;
            inference.buf_ready = 1;
        }
    }
}

void capture_samples(void* arg) {

  const int32_t i2s_bytes_to_read = sample_buffer_size;
  size_t bytes_read = i2s_bytes_to_read;
  int record_time = 2; //seconds
  int sampling_rate = 48000; //Hz
  int total_samples = record_time*sampling_rate;
  int sum_samples_read = 0;
  while (record_status & (sum_samples_read<total_samples)) {
    sum_samples_read+=i2s_bytes_to_read/4; // I2S_BIT_LENGTH for this test is 4
    if (sum_samples_read>total_samples) break;
    /* read data at once from i2s */
    dummy_i2s_channel_read( 1, sampleBuffer, i2s_bytes_to_read, &bytes_read, 100);

    if (bytes_read <= 0) {
      ei_printf("Error in I2S read : %d", bytes_read);
    }
    else {
        if (bytes_read < i2s_bytes_to_read) {
        ei_printf("Partial I2S read");
        }

        if (record_status) {
            audio_inference_callback(i2s_bytes_to_read);
        }
        else {
            break;
        }
    }
  }
  vTaskDelete(NULL);
}

bool microphone_inference_start(uint32_t n_samples)
{
    inference.buffers[0] = (int32_t *)malloc(n_samples * sizeof(int32_t));

    if (inference.buffers[0] == NULL) {
        return false;
    }

    inference.buffers[1] = (int32_t *)malloc(n_samples * sizeof(int32_t));

    if (inference.buffers[1] == NULL) {
        ei_free(inference.buffers[0]);
        return false;
    }

    inference.buf_select = 0;
    inference.buf_count = 0;
    inference.n_samples = n_samples;
    inference.buf_ready = 0;

    //if (i2s_init(EI_CLASSIFIER_FREQUENCY)) {
    //    ei_printf("Failed to start I2S!");
    //}

    ei_sleep(100);

    record_status = true;

    xTaskCreate(capture_samples, "CaptureSamples", 1024 * 32, (void*)sample_buffer_size, 10, NULL);

    return true;
}

bool microphone_inference_record(void)
{
    bool ret = true;
    if (inference.buf_ready == 1) {
        ei_printf(
            "Error sample buffer overrun. Decrease the number of slices per model window "
            "(EI_CLASSIFIER_SLICES_PER_MODEL_WINDOW)\n");
        ret = false;
    }
    while (inference.buf_ready == 0) {
        vTaskDelay(1);
    }

    inference.buf_ready = 0;
    return ret;
}

/**
 * Get raw audio signal data
 */
int microphone_audio_signal_get_data(size_t offset, size_t length, float *out_ptr)
{
    // Process the conversion to floats
    for (size_t i = 0; i < length; i++) {
        out_ptr[i] = static_cast<float>(inference.buffers[inference.buf_select ^ 1][offset+i]);
    }
    return 0;
}

void microphone_inference_end(void)
{
    //i2s_deinit();
    ei_free(inference.buffers[0]);
    ei_free(inference.buffers[1]);
}